 {"id":"flywheel_gateway-59c","title":"Comprehensive Notification System","description":"## Background

Effective observability requires proactive alerting when important events occur in the system. Users should not need to constantly monitor dashboards to stay informed about agent status changes, cost anomalies, conflict resolutions, or system issues. A comprehensive notification system bridges this gap by delivering relevant information through the user's preferred channels.

## Problem Statement

Currently, users must manually check the platform to discover issues or important events. This leads to delayed responses to critical situations (agent failures, cost overruns, conflicts requiring approval) and reduces overall platform effectiveness. Different users have different notification preferences - some prefer email digests while others need real-time Slack alerts for urgent issues.

## Technical Approach

### Notification Event Types

```typescript
// apps/gateway/src/types/notification.types.ts

type NotificationCategory = 
  | 'agent'      // Agent lifecycle events
  | 'conflict'   // Conflict detection and resolution
  | 'bead'       // Bead status changes
  | 'cost'       // Cost alerts and anomalies
  | 'system'     // System health and maintenance
  | 'security'   // Security-related events
  | 'team';      // Team and collaboration events

interface NotificationEvent {
  id: string;
  category: NotificationCategory;
  type: NotificationEventType;
  severity: 'info' | 'warning' | 'error' | 'critical';
  title: string;
  message: string;
  data: Record<string, any>; // Event-specific payload
  actorId?: string; // User/agent that triggered event
  targetId?: string; // Affected entity ID
  targetType?: string; // Entity type (agent, bead, etc.)
  orgId: string;
  timestamp: Date;
}

// Agent events
type AgentEventType = 
  | 'agent.created'
  | 'agent.started'
  | 'agent.stopped'
  | 'agent.error'
  | 'agent.recovered'
  | 'agent.rate_limited'
  | 'agent.quota_exceeded'
  | 'agent.config_changed';

// Conflict events
type ConflictEventType =
  | 'conflict.detected'
  | 'conflict.auto_resolved'
  | 'conflict.needs_review'
  | 'conflict.escalated'
  | 'conflict.resolved'
  | 'conflict.timeout';

// Cost events
type CostEventType =
  | 'cost.budget_warning'     // 80% threshold
  | 'cost.budget_critical'    // 95% threshold
  | 'cost.budget_exceeded'
  | 'cost.anomaly_detected'
  | 'cost.daily_summary'
  | 'cost.weekly_report';

// System events
type SystemEventType =
  | 'system.maintenance_scheduled'
  | 'system.maintenance_started'
  | 'system.maintenance_completed'
  | 'system.degraded_performance'
  | 'system.incident_started'
  | 'system.incident_resolved'
  | 'system.update_available';
```

### Multi-Channel Delivery Architecture

```typescript
// apps/gateway/src/services/notification.service.ts

interface NotificationService {
  // Core dispatch
  dispatch(event: NotificationEvent): Promise<void>;
  dispatchBatch(events: NotificationEvent[]): Promise<void>;

  // Channel-specific
  sendInApp(userId: string, notification: Notification): Promise<void>;
  sendEmail(userId: string, notification: Notification): Promise<void>;
  sendSlack(channelConfig: SlackConfig, notification: Notification): Promise<void>;
  sendWebhook(webhookConfig: WebhookConfig, notification: Notification): Promise<void>;

  // Digest management
  queueForDigest(userId: string, notification: Notification): Promise<void>;
  processDigests(frequency: 'daily' | 'weekly'): Promise<void>;
}

// Channel implementations
interface NotificationChannel {
  type: 'in_app' | 'email' | 'slack' | 'webhook';
  enabled: boolean;
  config: ChannelConfig;
  send(notification: FormattedNotification): Promise<DeliveryResult>;
}

interface SlackChannelConfig {
  webhookUrl: string;
  channel?: string; // Override default channel
  username?: string;
  iconEmoji?: string;
  mentionUsers?: string[]; // Slack user IDs for @mentions
  threadTs?: string; // For threaded replies
}

interface WebhookChannelConfig {
  url: string;
  method: 'POST' | 'PUT';
  headers: Record<string, string>;
  authType?: 'none' | 'basic' | 'bearer' | 'hmac';
  authConfig?: AuthConfig;
  retryPolicy: RetryPolicy;
  timeout: number;
}

interface EmailChannelConfig {
  provider: 'sendgrid' | 'ses' | 'smtp';
  fromAddress: string;
  replyTo?: string;
  templates: Map<NotificationEventType, string>;
}
```

### User Notification Preferences

```typescript
// apps/gateway/src/types/preferences.types.ts

interface NotificationPreferences {
  userId: string;
  orgId: string;

  // Global settings
  globalEnabled: boolean;

  // Per-category channel preferences
  categories: {
    [K in NotificationCategory]: CategoryPreference;
  };

  // Quiet hours
  quietHours: {
    enabled: boolean;
    timezone: string;
    schedule: WeeklySchedule;
    allowUrgent: boolean; // Bypass for critical notifications
  };

  // Digest preferences
  digest: {
    email: {
      enabled: boolean;
      frequency: 'daily' | 'weekly' | 'none';
      dayOfWeek?: number; // For weekly: 0-6
      timeOfDay: string; // HH:mm in user timezone
      includeCategories: NotificationCategory[];
    };
  };

  // Channel-specific configs
  channels: {
    inApp: { enabled: boolean };
    email: { 
      enabled: boolean;
      address?: string; // Override default
    };
    slack: {
      enabled: boolean;
      configs: SlackChannelConfig[];
    };
    webhooks: {
      enabled: boolean;
      configs: WebhookConfig[];
    };
  };
}

interface CategoryPreference {
  enabled: boolean;
  channels: ('in_app' | 'email' | 'slack' | 'webhook')[];
  minSeverity: 'info' | 'warning' | 'error' | 'critical';
  // Event-specific overrides
  eventOverrides?: {
    [eventType: string]: {
      enabled?: boolean;
      channels?: string[];
      minSeverity?: string;
    };
  };
}

interface WeeklySchedule {
  // Each day: array of quiet periods
  [day: number]: Array<{ start: string; end: string }>;
  // Example: { 0: [{ start: '22:00', end: '08:00' }] } // Sunday 10pm-8am
}
```

### Real-Time Notification Center

```typescript
// apps/web/src/components/notifications/NotificationCenter.tsx

interface NotificationCenterState {
  notifications: Notification[];
  unreadCount: number;
  isOpen: boolean;
  filter: NotificationFilter;
  isLoading: boolean;
}

interface NotificationFilter {
  categories?: NotificationCategory[];
  severities?: string[];
  dateRange?: { start: Date; end: Date };
  unreadOnly?: boolean;
  searchQuery?: string;
}

// WebSocket events for real-time updates
interface NotificationWebSocketEvents {
  'notification:new': (notification: Notification) => void;
  'notification:read': (notificationId: string) => void;
  'notification:batch_read': (notificationIds: string[]) => void;
  'unread_count:update': (count: number) => void;
}
```

### Database Schema

```sql
-- Notifications table
CREATE TABLE notifications (
  id UUID PRIMARY KEY,
  org_id UUID NOT NULL REFERENCES organizations(id),
  user_id UUID NOT NULL REFERENCES users(id),
  category VARCHAR(50) NOT NULL,
  event_type VARCHAR(100) NOT NULL,
  severity VARCHAR(20) NOT NULL,
  title VARCHAR(255) NOT NULL,
  message TEXT NOT NULL,
  data JSONB,
  actor_id UUID,
  target_id UUID,
  target_type VARCHAR(50),
  read_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  expires_at TIMESTAMPTZ -- For auto-cleanup
);

-- Indexes for common queries
CREATE INDEX idx_notifications_user_unread 
  ON notifications(user_id, created_at DESC) 
  WHERE read_at IS NULL;
CREATE INDEX idx_notifications_user_category 
  ON notifications(user_id, category, created_at DESC);
CREATE INDEX idx_notifications_org 
  ON notifications(org_id, created_at DESC);

-- Notification preferences
CREATE TABLE notification_preferences (
  user_id UUID PRIMARY KEY REFERENCES users(id),
  org_id UUID NOT NULL REFERENCES organizations(id),
  preferences JSONB NOT NULL,
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Digest queue for batching
CREATE TABLE notification_digest_queue (
  id UUID PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES users(id),
  notification_id UUID NOT NULL REFERENCES notifications(id),
  frequency VARCHAR(20) NOT NULL, -- 'daily' or 'weekly'
  scheduled_for TIMESTAMPTZ NOT NULL,
  processed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Delivery tracking
CREATE TABLE notification_deliveries (
  id UUID PRIMARY KEY,
  notification_id UUID NOT NULL REFERENCES notifications(id),
  channel VARCHAR(50) NOT NULL,
  status VARCHAR(20) NOT NULL, -- 'pending', 'sent', 'failed', 'retrying'
  attempts INTEGER DEFAULT 0,
  last_attempt_at TIMESTAMPTZ,
  error_message TEXT,
  delivered_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
```

